import{_ as o,o as a,c as i,a6 as n,c3 as s,c4 as r,bx as l,bC as d,b4 as c,b2 as p,b7 as h,c5 as u,c6 as t,am as g,c7 as m,c8 as y,c9 as b,ca as k,cb as f}from"./chunks/framework.UYVGz2W_.js";const S=JSON.parse('{"title":"Frequently Asked Questions","description":"","frontmatter":{},"headers":[],"relativePath":"faq/index.md","filePath":"faq/index.md"}'),T={name:"faq/index.md"};function v(_,e,P,w,I,A){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to “Frequently Asked Questions”">​</a></h1><p>This FAQ guide provides quick solutions to common Kitsu issues, such as login problems, task management, and production organization. Explore the sections below for step-by-step instructions and helpful tips. For further support, check the detailed <a href="./../configure-kitsu/">Kitsu documentation</a> or contact support.</p><hr><h2 id="login-issues" tabindex="-1">Login Issues <a class="header-anchor" href="#login-issues" aria-label="Permalink to “Login Issues”">​</a></h2><h3 id="i-can-t-log-in-to-kitsu-anymore" tabindex="-1">I can&#39;t log in to Kitsu anymore <a class="header-anchor" href="#i-can-t-log-in-to-kitsu-anymore" aria-label="Permalink to “I can&#39;t log in to Kitsu anymore”">​</a></h3><p>The first thing to check is the <strong>web address</strong> you are using to log in.</p><ul><li><p>If the web address is <strong>account.cg-wire.com/signin</strong> and you see the CGWire logo, you are on the <strong>wrong page</strong>.</p><p><img src="'+s+'" alt="Account login"></p><p>The <strong>account page</strong> is only for managing subscriptions, invoices, etc. You won&#39;t have access unless you&#39;ve registered for a subscription.</p></li><li><p>The correct web address for your Kitsu instance should look like <strong>your-studio-name.cg-wire.com</strong>. On this page, you&#39;ll be prompted to log in, and you should see the Kitsu logo.</p><p><img src="'+r+'" alt="Kitsu login"></p></li></ul><p>If you&#39;re unsure of the correct link:</p><ul><li>Check the invitation email you received.</li><li>Contact your studio manager for assistance.</li></ul><hr><h2 id="task-management" tabindex="-1">Task Management <a class="header-anchor" href="#task-management" aria-label="Permalink to “Task Management”">​</a></h2><h3 id="i-created-a-new-task-type-but-i-don-t-see-it-in-my-production" tabindex="-1">I created a new Task Type, but I don&#39;t see it in my production <a class="header-anchor" href="#i-created-a-new-task-type-but-i-don-t-see-it-in-my-production" aria-label="Permalink to “I created a new Task Type, but I don&#39;t see it in my production”">​</a></h3><p>If you&#39;ve created a new task type (<a href="./../configure-kitsu/#task-types">see documentation</a>) but it isn’t appearing in your production, it’s likely because task types need to be explicitly added to your <strong>Production Library</strong> after being created in the <strong>Studio Library</strong>.</p><h4 id="understanding-the-difference" tabindex="-1">Understanding the Difference: <a class="header-anchor" href="#understanding-the-difference" aria-label="Permalink to “Understanding the Difference:”">​</a></h4><ul><li><strong>Studio Library</strong>: This is where all task types are initially created and stored for your studio.</li><li><strong>Production Library</strong>: Each production has its own library, and task types must be added here before they can be used within that production.</li></ul><h4 id="steps-to-add-task-types-to-your-production" tabindex="-1">Steps to Add Task Types to Your Production <a class="header-anchor" href="#steps-to-add-task-types-to-your-production" aria-label="Permalink to “Steps to Add Task Types to Your Production”">​</a></h4><ol><li><p>Go to your production <strong>Settings</strong> page from the navigation menu.<br><img src="'+l+'" alt="Production Settings page"></p></li><li><p>Navigate to the <strong>Task Types</strong> tab.<br><img src="'+d+'" alt="Task Type Settings page"></p></li><li><p>Select the appropriate entity tab (e.g., assets, shots, sequences, episodes, edits).</p></li><li><p>Find your task type in the list on the right and click to add it.</p></li></ol><p>Once added, go back to your entity page and click <strong>Add Task Type</strong>.<br><img src="'+c+'" alt="Add Task Type"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p><strong>Permissions</strong>:<br> If you can&#39;t see the <strong>Settings</strong> option in the main menu, you may not have the necessary permissions. Please contact your studio administrator if you do not have this option.</p></div><hr><h3 id="my-task-type-columns-are-not-in-the-right-order" tabindex="-1">My Task Type columns are not in the right order <a class="header-anchor" href="#my-task-type-columns-are-not-in-the-right-order" aria-label="Permalink to “My Task Type columns are not in the right order”">​</a></h3><p>If task type columns appear out of order, you can adjust them:</p><ul><li><p><strong>Studio-wide order</strong>:</p><ol><li>Go to the main menu under the <strong>ADMIN</strong> section and click <strong>Task Types</strong>.<br><img src="'+p+'" alt="Task Type admin Menu"></li><li>Drag and drop task types into the desired order.<br><img src="'+h+'" alt="Task Type order"></li></ol></li><li><p><strong>Production-specific order</strong>:</p><ol><li>Go to the <strong>Settings</strong> page for your production.</li><li>Navigate to the <strong>Task Types</strong> tab and adjust the order by dragging and dropping.</li></ol></li></ul><hr><h3 id="task-type-columns-are-missing" tabindex="-1">Task Type columns are missing <a class="header-anchor" href="#task-type-columns-are-missing" aria-label="Permalink to “Task Type columns are missing”">​</a></h3><p>If some task type columns are missing on the entity page:</p><ol><li><p>Check the department filter and ensure it is set to <strong>All Departments</strong>.<br><img src="'+u+'" alt="Department filtered view"></p></li><li><p>Ensure the <strong>Show additional information</strong> button is highlighted.<br><img src="'+t+'" alt="Hide option"></p></li><li><p>If columns are reduced, they won&#39;t display unless additional information is shown.</p></li></ol><hr><h2 id="team-and-assignments" tabindex="-1">Team and Assignments <a class="header-anchor" href="#team-and-assignments" aria-label="Permalink to “Team and Assignments”">​</a></h2><h3 id="i-can-t-assign-anyone-to-a-task" tabindex="-1">I can&#39;t assign anyone to a task <a class="header-anchor" href="#i-can-t-assign-anyone-to-a-task" aria-label="Permalink to “I can&#39;t assign anyone to a task”">​</a></h3><p>If the list of assignees in the comment panel is empty, it means the people you&#39;ve added to the <strong>People</strong> page haven&#39;t been added to the production.</p><h4 id="steps-to-add-people-to-a-production" tabindex="-1">Steps to Add People to a Production <a class="header-anchor" href="#steps-to-add-people-to-a-production" aria-label="Permalink to “Steps to Add People to a Production”">​</a></h4><ol><li><p>Navigate to the <strong>Team</strong> page from the production menu.<br><img src="'+g+'" alt="Team menu"></p></li><li><p>The <strong>Team</strong> page will be empty, but you&#39;ll see a list of people on the right.<br><img src="'+m+'" alt="Team page empty"></p></li><li><p>Add people individually or by department.</p></li></ol><p>Once added, they&#39;ll have access to the production, and you can assign them tasks.</p><hr><h3 id="all-assignments-have-disappeared" tabindex="-1">All assignments have disappeared <a class="header-anchor" href="#all-assignments-have-disappeared" aria-label="Permalink to “All assignments have disappeared”">​</a></h3><p>If assignees&#39; avatars are no longer visible:</p><ol><li><p>Ensure you haven’t accidentally clicked the <strong>Hide Assignments</strong> button.<br><img src="'+t+'" alt="Hide option"></p></li><li><p>Click the button again to make the avatars reappear.</p></li></ol><hr><h2 id="production-management" tabindex="-1">Production Management <a class="header-anchor" href="#production-management" aria-label="Permalink to “Production Management”">​</a></h2><h3 id="how-to-delete-or-archive-a-production" tabindex="-1">How to Delete or Archive a Production <a class="header-anchor" href="#how-to-delete-or-archive-a-production" aria-label="Permalink to “How to Delete or Archive a Production”">​</a></h3><p>If you no longer need access to a production, you can choose to archive or delete it.</p><ul><li><strong>Archiving</strong>: This will remove the production from the navigation menu but keep it accessible for reference.</li><li><strong>Deleting</strong>: This is a permanent, non-reversible action that will completely remove the production from your Kitsu instance.</li></ul><h4 id="steps-to-archive-a-production" tabindex="-1">Steps to Archive a Production <a class="header-anchor" href="#steps-to-archive-a-production" aria-label="Permalink to “Steps to Archive a Production”">​</a></h4><ol><li><p>Go to the main menu and select <strong>Productions</strong> under the <strong>STUDIO</strong> section.<br><img src="'+y+'" alt="Main Menu Productions"></p></li><li><p>Locate the production you want to archive and click the edit button.<br><img src="'+b+'" alt="Edit Productions"></p></li><li><p>Change the <strong>Status</strong> from <strong>Open</strong> to <strong>Closed</strong> and confirm.<br><img src="'+k+'" alt="Edit Productions option"></p></li></ol><p>The production is now archived and will no longer appear in the navigation menu.</p><hr><h4 id="steps-to-delete-a-production" tabindex="-1">Steps to Delete a Production <a class="header-anchor" href="#steps-to-delete-a-production" aria-label="Permalink to “Steps to Delete a Production”">​</a></h4><p>Only archived productions can be deleted. If you&#39;re sure you want to permanently remove a production:</p><ol><li>From the <strong>Productions</strong> list, hover over the archived (closed) production. A trash icon will appear.</li><li>Click the trash icon, and a confirmation dialog will open.</li><li>Type the name of the production to confirm the deletion.</li></ol><p><img src="'+f+'" alt="Delete Production"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Deleting a production is permanent and cannot be undone. Only proceed if you’re certain the data is no longer needed.</p></div><hr><h2 id="miscellaneous" tabindex="-1">Miscellaneous <a class="header-anchor" href="#miscellaneous" aria-label="Permalink to “Miscellaneous”">​</a></h2><h3 id="where-can-i-see-the-storage-i-m-using" tabindex="-1">Where can I see the storage I&#39;m using? <a class="header-anchor" href="#where-can-i-see-the-storage-i-m-using" aria-label="Permalink to “Where can I see the storage I&#39;m using?”">​</a></h3><p>Currently, Kitsu does not display storage usage directly in the interface or on your account page. This means you won&#39;t find a section in the app showing how much storage your productions or assets are consuming.</p><p>If you need to check your storage usage:</p><ul><li>Contact your system administrator or IT team if Kitsu is hosted on your studio&#39;s servers.</li><li>If you&#39;re using a cloud-hosted Kitsu instance, email <strong><a href="mailto:support@cg-wire.com" target="_blank" rel="noreferrer">support@cg-wire.com</a></strong> with your studio name and account details, where our team can provide you with the necessary information.</li></ul>',58)])])}const D=o(T,[["render",v]]);export{S as __pageData,D as default};
